<template><div class='modern-page'><section class='modern-hero'><h1>Notificações</h1><p>Logs de mensagens enviadas e falhadas, com reenvio e rastreabilidade.</p><div class='hero-actions'><button class='btn btn-primary' @click='retryAll'>Reenviar falhadas</button><button class='btn' @click="toast.success('Logs exportados')">Exportar logs</button><span class='hero-chip'>Email · SMS · WhatsApp</span></div></section><div class='kpi-grid'><div class='kpi good'><div class='label'>Enviadas</div><div class='value'>{{sent}}</div><div class='note'>Sucesso</div></div><div class='kpi danger'><div class='label'>Falhadas</div><div class='value'>{{failed}}</div><div class='note'>Reenvio</div></div><div class='kpi'><div class='label'>Total</div><div class='value'>{{logs.length}}</div><div class='note'>Eventos</div></div><div class='kpi warn'><div class='label'>Tentativas</div><div class='value'>3x</div><div class='note'>Backoff</div></div></div><div class='modern-card'><h2>Logs</h2><table class='modern-table'><thead><tr><th>Data</th><th>Canal</th><th>Evento</th><th>Destino</th><th>Status</th><th>Acções</th></tr></thead><tbody><tr v-for='l in logs' :key='l.id'><td>{{l.date}}</td><td>{{l.channel}}</td><td>{{l.event}}</td><td>{{l.to}}</td><td><span :class='st(l.status)'>{{l.status==='sent'?'Enviada':'Falhada'}}</span></td><td><button v-if='l.status==="failed"' class='btn btn-sm btn-danger-soft' @click='retry(l)'>Reenviar</button><button class='btn btn-sm' @click="toast.info(l.channel+': '+l.event)">Ver log</button></td></tr></tbody></table></div></div></template><script setup>
import { ref, computed } from 'vue'; import { useToast } from 'vue-toastification'; const toast=useToast(); function mzn(v){return Number(v||0).toLocaleString('pt-MZ',{style:'currency',currency:'MZN',maximumFractionDigits:0})} function st(s){return 'status-pill st-'+s}
const logs=ref([{id:1,date:'05/05 14:32',channel:'Email',event:'Pedido aprovado',to:'maria@gmail.com',status:'sent'},{id:2,date:'05/05 14:33',channel:'SMS',event:'Pedido aprovado',to:'+258842345678',status:'sent'},{id:3,date:'05/05 15:10',channel:'WhatsApp',event:'Pagamento em atraso',to:'+258869876543',status:'failed'}]); const sent=computed(()=>logs.value.filter(l=>l.status==='sent').length); const failed=computed(()=>logs.value.filter(l=>l.status==='failed').length); function retry(l){l.status='sent';toast.success('Notificação reenviada')} function retryAll(){logs.value.forEach(l=>l.status='sent');toast.success('Falhadas reenviadas')}
</script>